SELECT MIN(?duration) AS ?shortest
WHERE {
  ?nlcs wdt:P31 wd:Q2477512 ;
         wdt:P585 ?date.
  FILTER (strstarts(str(?date), "1977") || strstarts(str(?date), "1978") || strstarts(str(?date), "2008") || strstarts(str(?date), "2009"))
  ?nlcs wdt:P527 ?game.
  ?game wdt:P132 wd:Q583215.
  ?game wdt:P132 wd:Q174333.
  ?game wdt:P1049 ?duration.
}

SELECT (MIN(?duration) AS ?shortest)
WHERE {
  ?nlcs wdt:P31 wd:Q2477512 ;
         wdt:P585 ?date.
  FILTER (STRSTARTS(STR(?date), "1977") || STRSTARTS(STR(?date), "1978") || STRSTARTS(STR(?date), "2008") || STRSTARTS(STR(?date), "2009"))
  ?nlcs wdt:P527 ?game.
  ?game wdt:P132 wd:Q583215.
  ?game wdt:P132 wd:Q174333.
  ?game wdt:P1049 ?duration.
}

SELECT (MIN(?duration) AS ?shortest)
WHERE {
  ?competition wdt:P31 wd:Q2852059 ;
             wdt:P154 wd:Q583215 ;
             wdt:P154 wd:Q174333 ;
             wdt:P585 ?date.
  FILTER (STRSTARTS(STR(?date), "1977") || STRSTARTS(STR(?date), "1978") || STRSTARTS(STR(?date), "2008") || STRSTARTS(STR(?date), "2009"))
  ?competition wdt:P527 ?game.
  ?game wdt:P1049 ?duration.
}
LIMIT 1
